targets.expr:
sum by (name_label) (
  rate(
    label_replace(
      {database="$database", container="ydb-dynamic", __name__=~"kqp_Issues_YQL:.+"},
      "name_label", "$1", "__name__", "kqp_Issues_YQL:(.+)"
    )[$__rate_interval:]
  )
) or
label_replace(vector(0), "name_label", "No Errors", "", "")
